func ports(host, container uint) []Port {
	if host == 0 {
		return nil
	}

	return []Port{
		{
			Mode:      "ingress",
			Target:    container,
			Published: strconv.FormatUint(uint64(host), 10),
			Protocol:  "tcp",
		},
	}
}

