type ExposePorts struct {
	Auth      uint
	Storage   uint
	Graphql   uint
	Console   uint
	Functions uint
}

func sanitizeBranch(name string) string {
	re := regexp.MustCompile(`[^a-zA-Z0-9_-]`)
	return strings.ToLower(re.ReplaceAllString(name, ""))
}

func IsJWTSecretCompatibleWithHasuraAuth( //nolint:cyclop
	jwtSecret *model.ConfigJWTSecret,
) bool {
	if jwtSecret != nil && jwtSecret.Type != nil && *jwtSecret.Type != "" && jwtSecret.Key != nil &&
		*jwtSecret.Key != "" {
		return *jwtSecret.Type == "HS256" || *jwtSecret.Type == "HS384" ||
			*jwtSecret.Type == "HS512" || *jwtSecret.Type == "RS256" ||
			*jwtSecret.Type == "RS384" || *jwtSecret.Type == "RS512"
	}

	return false
}

func getServices( //nolint: funlen,cyclop
	cfg *model.ConfigConfig,
	subdomain string,
	projectName string,
	httpPort uint,
	useTLS bool,
	postgresPort uint,
	nhostFolder string,
	dotNhostFolder string,
	rootFolder string,
	ports ExposePorts,
	branch string,
	dashboardVersion string,
	functionsVersion string,
	configserviceImage string,
	startFunctions bool,
	runServices ...*RunService,
) (map[string]*Service, error) {
	minioVolumeName := "minio_" + sanitizeBranch(branch)
	minio := minio(subdomain, minioVolumeName)

	storage, err := storage(cfg, subdomain, useTLS, httpPort, ports.Storage)
	if err != nil {
		return nil, err
	}

	pgVolumeName := "pgdata_" + sanitizeBranch(branch)
	dataFolder := filepath.Join(dotNhostFolder, "data")

	postgres, err := postgres(cfg, subdomain, postgresPort, dataFolder, pgVolumeName)
	if err != nil {
		return nil, err
	}

	graphql, err := graphql(cfg, subdomain, useTLS, httpPort, ports.Graphql)
	if err != nil {
		return nil, err
	}

	jwtSecret := graphql.Environment["HASURA_GRAPHQL_JWT_SECRET"]

	console, err := console(cfg, subdomain, httpPort, useTLS, nhostFolder, ports.Console)
	if err != nil {
		return nil, err
	}

	traefik, err := traefik(subdomain, projectName, httpPort, dotNhostFolder)
	if err != nil {
		return nil, err
	}

	mailhogVolumeName := "mailhog_" + sanitizeBranch(branch)
	mailhog := mailhog(subdomain, mailhogVolumeName, useTLS)

	cs, err := configserver(
		configserviceImage,
		rootFolder,
		nhostFolder,
		projectName,
		useTLS,
		runServices...,
	)
	if err != nil {
		return nil, err
	}

	services := map[string]*Service{
		"console":      console,
		"dashboard":    dashboard(cfg, subdomain, dashboardVersion, httpPort, useTLS),
		"graphql":      graphql,
		"minio":        minio,
		"postgres":     postgres,
		"storage":      storage,
		"mailhog":      mailhog,
		"traefik":      traefik,
		"configserver": cs,
	}

	if startFunctions {
		services["functions"], err = functions(
			cfg,
			subdomain,
			httpPort,
			useTLS,
			rootFolder,
			jwtSecret,
			ports.Functions,
			branch,
			functionsVersion,
		)
		if err != nil {
			return nil, err
		}
	}

	if len(cfg.GetHasura().GetJwtSecrets()) > 0 &&
		IsJWTSecretCompatibleWithHasuraAuth(cfg.GetHasura().GetJwtSecrets()[0]) &&
		cfg.GetHasura().GetAuthHook() == nil {
		auth, err := auth(cfg, subdomain, httpPort, useTLS, nhostFolder, ports.Auth)
		if err != nil {
			return nil, err
		}

		services["auth"] = auth

		if cfg.Ai != nil {
			services["ai"] = ai(cfg, subdomain)
		}
	}

	for _, runService := range runServices {
		svc := run(runService.Config, subdomain, branch)

		if len(runService.BindMounts) > 0 {
			svc.Volumes = append(svc.Volumes, runService.BindMounts...)
		}

		services["run-"+runService.Config.Name] = svc
	}

	return services, nil
}

type RunService struct {
	Config     *model.ConfigRunServiceConfig
	Path       string
	BindMounts []Volume
}

func mountCACertificates(
	path string,
	services map[string]*Service,
) {
	for _, service := range services {
		service.Volumes = append(service.Volumes, Volume{
			Type:     "bind",
			Source:   path,
			Target:   "/etc/ssl/certs/ca-certificates.crt",
			ReadOnly: new(true),
		})
	}
}

func ComposeFileFromConfig(
	cfg *model.ConfigConfig,
	subdomain string,
	projectName string,
	httpPort uint,
	useTLS bool,
	postgresPort uint,
	nhostFolder string,
	dotNhostFolder string,
	rootFolder string,
	ports ExposePorts,
	branch string,
	dashboardVersion string,
	functionsVersion string,
	configserverImage string,
	startFunctions bool,
	caCertificatesPath string,
	runServices ...*RunService,
) (*ComposeFile, error) {
	services, err := getServices(
		cfg,
		subdomain,
		projectName,
		httpPort,
		useTLS,
		postgresPort,
		nhostFolder,
		dotNhostFolder,
		rootFolder,
		ports,
		branch,
		dashboardVersion,
		functionsVersion,
		configserverImage,
		startFunctions,
		runServices...,
	)
	if err != nil {
		return nil, err
	}

	volumes := map[string]struct{}{
		rootNodeModules(branch):             {},
		"pgdata_" + sanitizeBranch(branch):  {},
		"minio_" + sanitizeBranch(branch):   {},
		"mailhog_" + sanitizeBranch(branch): {},
	}

	if startFunctions {
		volumes[functionsNodeModules(branch)] = struct{}{}
	}

	for _, runService := range runServices {
		for _, s := range runService.Config.GetResources().GetStorage() {
			volumes[runVolumeName(runService.Config.Name, s.GetName(), branch)] = struct{}{}
		}
	}

	if caCertificatesPath != "" {
		mountCACertificates(caCertificatesPath, services)
	}

	return &ComposeFile{
		Services: services,
		Volumes:  volumes,
	}, nil
}

