 6	 * It creates a new Apollo Client instance that connects to the local mimir when running the a local nhost project
 7	 * @returns A function that returns a new ApolloClient instance.
 8	 */
 9	export default function useLocalMimirClient() {
10	  return useMemo(
11	    () =>
12	      new ApolloClient({
13	        cache: new InMemoryCache(),
14	        link: new HttpLink({
15	          uri: getConfigServerUrl(),
16	          headers: {
17	            'x-hasura-admin-secret': getHasuraAdminSecret(),
18	          },
19	        }),
20	      }),
21	    [],
22	  );
23	}

