 12	func TestAdminSecretAuth(t *testing.T) {
 13		gin.SetMode(gin.TestMode)
 14	
 15		cases := []struct {
 16			name       string
 17			path       string
 18			method     string
 19			header     string
 20			wantStatus int
 21		}{
 22			{
 23				name:       "allows matching admin secret",
 24				path:       "/v1/configserver/graphql",
 25				method:     http.MethodPost,
 26				header:     "secret",
 27				wantStatus: http.StatusOK,
 28			},
 29			{
 30				name:       "rejects missing admin secret",
 31				path:       "/v1/configserver/graphql",
 32				method:     http.MethodPost,
 33				wantStatus: http.StatusUnauthorized,
 34			},
 35			{
 36				name:       "rejects wrong admin secret",
 37				path:       "/v1/configserver/graphql",
 38				method:     http.MethodPost,
 39				header:     "wrong",
 40				wantStatus: http.StatusUnauthorized,
 41			},
 42			{
 43				name:       "allows health checks",
 44				path:       "/healthz",
 45				method:     http.MethodGet,
 46				wantStatus: http.StatusOK,
 47			},
 48			{
 49				name:       "allows preflight requests",
 50				path:       "/v1/configserver/graphql",
 51				method:     http.MethodOptions,
 52				wantStatus: http.StatusOK,
 53			},
 54		}
 55	
 56		for _, tc := range cases {
 57			t.Run(tc.name, func(t *testing.T) {
 58				r := gin.New()
 59				r.Use(adminSecretAuth("secret"))
 60				r.Any("/*path", func(c *gin.Context) {
 61					c.Status(http.StatusOK)
 62				})
 63	
 64				req := httptest.NewRequest(tc.method, tc.path, nil)
 65				if tc.header != "" {
 66					req.Header.Set(adminSecretHeader, tc.header)
 67				}
 68	
 69				w := httptest.NewRecorder()
 70				r.ServeHTTP(w, req)
 71	
 72				if w.Code != tc.wantStatus {
 73					t.Fatalf("status = %d, want %d", w.Code, tc.wantStatus)
 74				}
 75			})
 76		}
 77	}
