 79	func TestWebSocketAdminSecretAuth(t *testing.T) {
 80		t.Parallel()
 81	
 82		init := webSocketAdminSecretAuth("secret")
 83	
 84		if _, _, err := init(t.Context(), transport.InitPayload{
 85			"headers": map[string]any{
 86				"X-Hasura-Admin-Secret": "secret",
 87			},
 88		}); err != nil {
 89			t.Fatalf("expected matching secret to pass: %v", err)
 90		}
 91	
 92		if _, _, err := init(t.Context(), transport.InitPayload{
 93			"headers": map[string]any{
 94				"X-Hasura-Admin-Secret": "wrong",
 95			},
 96		}); err == nil {
 97			t.Fatal("expected wrong secret to fail")
 98		}
 99	}
