101	func TestIsAllowedDashboardOrigin(t *testing.T) {
102		t.Parallel()
103	
104		cases := []struct {
105			name   string
106			origin string
107			want   bool
108		}{
109			{
110				name:   "allows local dashboard host",
111				origin: "https://local.dashboard.local.nhost.run",
112				want:   true,
113			},
114			{
115				name:   "allows localhost development",
116				origin: "http://localhost:3000",
117				want:   true,
118			},
119			{
120				name:   "rejects arbitrary origin",
121				origin: "https://example.com",
122				want:   false,
123			},
124		}
125	
126		for _, tc := range cases {
127			t.Run(tc.name, func(t *testing.T) {
128				t.Parallel()
129	
130				if got := isAllowedDashboardOrigin(tc.origin); got != tc.want {
131					t.Fatalf("isAllowedDashboardOrigin() = %t, want %t", got, tc.want)
132				}
133			})
134		}
135	}
